import React, { useState, useEffect, useMemo } from 'react';
import { useLocation } from 'react-router-dom';
import { motion, useReducedMotion } from 'framer-motion';
import { 
  Plus, Minus, MapPin, Clock, 
  Utensils, TreePine, Palette, Music, 
  Ticket, Beer, Zap 
} from 'lucide-react';
import Reveal from '../components/Reveal';
import { getMotionPresets } from '../ui/motion';
import Skeleton from '../components/Skeleton';
import PageLayout from '../components/PageLayout';

const Itinerary: React.FC = () => {
  const location = useLocation();
  const reduceMotion = useReducedMotion() ?? false;
  const motionPresets = React.useMemo(() => getMotionPresets(reduceMotion), [reduceMotion]);

  const selections = location.state?.selections || {
    persona: 'The Soloist',
    budget: 500,
    hours: 24,
  };

  const [suggestions, setSuggestions] = useState<any[]>([]);
  const [myPlan, setMyPlan] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [weather, setWeather] = useState<any>(null);

  // Helper to get icons based on activity name
  const getIcon = (activity: string) => {
    const text = activity.toLowerCase();
    if (text.includes('food') || text.includes('hall') || text.includes('sushi')) return <Utensils size={18} />;
    if (text.includes('park') || text.includes('nature') || text.includes('whitewater')) return <TreePine size={18} />;
    if (text.includes('museum') || text.includes('art')) return <Palette size={18} />;
    if (text.includes('music') || text.includes('jazz')) return <Music size={18} />;
    if (text.includes('brewery') || text.includes('bar')) return <Beer size={18} />;
    return <Ticket size={18} />;
  };

  // Calculate Budget Spent
  const budgetSpent = useMemo(() => {
    return myPlan.reduce((acc, curr) => {
        const costStr = curr.cost || "$$";
        return acc + (costStr.length * 25); // Simple math: $ = 25, $$ = 50, etc.
    }, 0);
  }, [myPlan]);

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      try {
        const attRes = await fetch('http://127.0.0.1:8000/api/attractions/generate', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(selections),
        });
        const attData = await attRes.json();
        setSuggestions(attData);

        const weathRes = await fetch('http://127.0.0.1:8000/api/weather/forecast');
        const weathData = await weathRes.json();
        setWeather(weathData);
      } catch (err) {
        console.error("Link failure:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  const addToPlan = (spot: any) => {
    setMyPlan(prev => [...prev, spot]); 
    setSuggestions(prev => prev.filter(item => item.id !== spot.id));
  };

  const removeFromPlan = (spot: any) => {
    setSuggestions(prev => [spot, ...prev]);
    setMyPlan(prev => prev.filter(item => item.id !== spot.id));
  };

  return (
    <div className="min-h-screen bg-[#2B2B2B] text-[#F1E7C8] font-inter selection:bg-[#D4AF37] selection:text-[#2B2B2B]">
      <PageLayout contentClassName="max-w-7xl">
      <div className="mx-auto grid w-full max-w-7xl grid-cols-1 gap-10 lg:grid-cols-12 lg:gap-20">

        {/* SIDEBAR: TRIP HUD */}
        <div className="lg:col-span-4">
          <Reveal>
              <div className="glass-card sticky top-28 rounded-[2.5rem] border-white/10 bg-gradient-to-br from-white/[0.07] to-transparent p-8">
                <h1 className="text-6xl mb-2 font-serif italic text-[#D4AF37] serif-glow leading-tight">Safari</h1>
                <p className="text-[10px] uppercase tracking-[0.34em] text-white/35 font-black mb-8">Personalized Itinerary</p>

                <div className="space-y-6 mb-10">
                    <div className="flex justify-between items-end">
                        <div>
                            <p className="text-[9px] uppercase text-white/45 font-bold mb-1">Current Vibe</p>
                            <span className="text-xl font-serif italic text-[#D4AF37]">{selections.persona}</span>
                        </div>
                        <Zap size={16} className="text-[#D4AF37] opacity-50 mb-1" />
                    </div>

                    <div>
                        <div className="flex justify-between items-end mb-2">
                            <p className="text-[9px] uppercase text-white/45 font-bold">Budget Usage</p>
                            <span className="text-xs font-black text-gold">${budgetSpent} / ${selections.budget}</span>
                        </div>
                        <div className="h-1.5 w-full rounded-full bg-white/10 overflow-hidden">
                            <div 
                                className="h-full bg-emerald transition-all duration-700 ease-out" 
                                style={{ width: `${Math.min((budgetSpent / selections.budget) * 100, 100)}%` }}
                            />
                        </div>
                    </div>
                </div>

                {!weather && loading && (
                  <div className="pt-8 border-t border-white/5">
                    <div className="flex items-center justify-between">
                      <div className="space-y-3">
                        <Skeleton className="h-10 w-28" />
                        <Skeleton className="h-3 w-40" />
                      </div>
                      <Skeleton className="h-10 w-10 rounded-full" />
                    </div>
                  </div>
                )}

                {weather && (
                  <div className="pt-8 border-t border-white/5 flex items-center justify-between">
                    <div className="flex items-center gap-4">
                        <div className="text-5xl font-serif italic text-[#D4AF37] leading-none">{weather.current_temp}°</div>
                        <div className="text-[10px] uppercase font-black text-white/40">{weather.description}</div>
                    </div>
                    <img loading="lazy" decoding="async" src={`http://openweathermap.org/img/wn/${weather.hourly?.[0]?.icon}.png`} className="w-10 h-10 opacity-60" alt="weather icon" />
                  </div>
                )}
            </div>
            </Reveal>
        </div>

        {/* MAIN FEED: THE PLANNER */}
        <div className="lg:col-span-8 space-y-14">

            {/* 1. MY PLAN (Active View) */}
            <Reveal>
            <section className="relative">
                <div className="mb-10 flex items-center justify-between">
                  <h2 className="text-xs font-black uppercase tracking-[0.5em] text-gold flex items-center gap-3">
                    <div className="h-2 w-2 rounded-full bg-gold animate-pulse" /> My Schedule
                  </h2>
                </div>

                {myPlan.length === 0 ? (
                    <div className="group glass min-h-[22rem] rounded-[3rem] border border-white/5 bg-white/[0.01] p-20 text-center transition-all cursor-default hover:bg-white/[0.03] flex flex-col items-center justify-center">
                        <div className="inline-flex p-4 rounded-full bg-white/5 text-white/10 mb-6 group-hover:scale-110 transition-transform">
                            <Clock size={32} />
                        </div>
                        <p className="text-white/20 font-serif text-xl italic">Empty schedule. Pick your first adventure.</p>
                    </div>
                ) : (
                    <div className="space-y-4 relative">
                        {/* THE PATH LINE (Visual flow) */}
                        <div className="absolute left-8 top-10 bottom-10 w-px bg-gradient-to-b from-emerald/50 via-bone-white/10 to-transparent hidden md:block" />

                        {myPlan.map((spot, idx) => (
                            <div key={spot.id} className="glass ml-0 md:ml-12 p-6 rounded-[2rem] border border-white/10 flex justify-between items-center group relative hover:border-emerald/40 transition-all shadow-xl">
                              <div className="absolute -left-[3.25rem] w-4 h-4 rounded-full bg-[#2B2B2B] border-2 border-emerald hidden md:block" />
                                <div className="flex items-center gap-6">
                                    <div className="p-4 bg-emerald/10 text-bone-white rounded-2xl">
                                        {getIcon(spot.activity)}
                                    </div>
                                    <div>
                                        <div className="text-[10px] text-gold font-black tracking-widest uppercase mb-1">{spot.time || 'Next Up'}</div>
                                        <h3 className="text-2xl font-serif italic text-white">{spot.activity}</h3>
                                        <p className="flex items-center gap-1 text-xs font-medium tracking-wide text-white/45">
                                            <MapPin size={12} /> {spot.location}
                                        </p>
                                    </div>
                                </div>
                                    <button onClick={() => removeFromPlan(spot)} className="rounded-2xl border border-white/10 bg-white/[0.04] p-4 text-white/40 transition-all hover:border-gold/45 hover:bg-gold/10 hover:text-gold">
                                  <Minus size={20} />
                                </button>
                            </div>
                        ))}
                    </div>
                )}
            </section>
                </Reveal>

            {/* 2. SUGGESTIONS GRID */}
                <Reveal delay={0.06}>
                <section>
                <div className="mb-12 flex items-end justify-between">
                  <div className="space-y-3">
                    <h2 className="text-xs font-black uppercase tracking-[0.5em] text-[#D4AF37]">Live Discoveries</h2>
                        <p className="text-xl italic leading-none text-white/52 font-serif">The pulse of the Queen City</p>
                    </div>
                    {loading && (
                      <motion.div
                        variants={motionPresets.fadeUp}
                        initial="hidden"
                        animate="show"
                        className="flex items-center gap-2 rounded-full border border-stroke bg-white/[0.04] px-3 py-1.5"
                        aria-label="Loading discoveries"
                      >
                        <span className="h-2 w-2 animate-pulse rounded-full bg-emerald" />
                        <span className="h-2 w-2 animate-pulse rounded-full bg-gold [animation-delay:140ms]" />
                        <span className="h-2 w-2 animate-pulse rounded-full bg-emerald [animation-delay:280ms]" />
                      </motion.div>
                    )}
                </div>

                <div className="grid grid-cols-1 gap-8 md:grid-cols-2">
                    {loading && suggestions.length === 0 && (
                      <>
                        {[0, 1, 2, 3].map((skeleton) => (
                          <motion.div
                            key={`skeleton-${skeleton}`}
                            variants={motionPresets.fadeUp}
                            initial="hidden"
                            animate="show"
                            transition={{ delay: skeleton * 0.05 }}
                            className="glass-card relative overflow-hidden rounded-[2.5rem] border-white/10 p-8"
                          >
                            <div className="space-y-5">
                              <Skeleton className="h-10 w-10 rounded-xl" />
                              <Skeleton className="h-7 w-4/5" />
                              <Skeleton className="h-4 w-full" />
                              <Skeleton className="h-4 w-5/6" />
                              <Skeleton className="h-12 w-full rounded-2xl" />
                            </div>
                          </motion.div>
                        ))}
                      </>
                    )}

                    {suggestions.map((spot) => (
                        <div key={spot.id} className="glass-card group relative flex flex-col justify-between overflow-hidden rounded-[2.5rem] border-white/10 p-8 transition-all hover:border-[#D4AF37]/40 hover:bg-white/[0.06]">
                            {/* Decorative background glow */}
                            <div className="absolute -top-24 -right-24 w-48 h-48 bg-[#D4AF37]/5 rounded-full blur-3xl group-hover:bg-[#D4AF37]/10 transition-colors" />

                            <div>
                                <div className="flex justify-between items-start mb-8">
                                    <div className="p-3 bg-white/5 rounded-xl text-[#D4AF37] group-hover:scale-110 transition-transform">
                                        {getIcon(spot.activity)}
                                    </div>
                                    <div className="flex flex-col items-end">
                                        <span className="text-[10px] font-black tracking-[0.2em] text-[#D4AF37] uppercase mb-1">{spot.drive_time}</span>
                                        <span className="text-xs font-black text-gold/85 tracking-tighter">{spot.cost}</span>
                                    </div>
                                </div>
                                <h3 className="text-2xl font-serif italic mb-3 text-white leading-snug group-hover:text-[#D4AF37] transition-colors">{spot.activity}</h3>
                                <p className="mb-10 line-clamp-3 text-sm font-light leading-relaxed text-white/55">"{spot.description}"</p>
                            </div>

                            <button 
                              onClick={() => addToPlan(spot)} 
                              className="w-full rounded-2xl border border-white/14 bg-white/[0.05] py-4 text-[10px] font-black uppercase tracking-[0.24em] shadow-lg transition-all hover:border-[#D4AF37] hover:bg-[#D4AF37] hover:text-[#2B2B2B] active:scale-95"
                            >
                                <Plus size={14} className="inline mr-2" /> Add Destination
                            </button>
                        </div>
                    ))}
                </div>
            </section>
            </Reveal>
        </div>
      </div>
      </PageLayout>
    </div>
  );
};

export default Itinerary;
